#include <stdio.h>
#include <stdlib.h>

int max(int a, int b) { return a > b ? a : b; }

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int* A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int*** dp = (int***)malloc(N * sizeof(int**));
        for (int i = 0; i < N; i++) {
            dp[i] = (int**)malloc(K * sizeof(int*));
            for (int j = 0; j < K; j++) {
                dp[i][j] = (int*)malloc(N * sizeof(int));
                for (int k = 0; k < N; k++) {
                    dp[i][j][k] = 0;
                }
            }
        }
        for (int i = 0; i < N; i++) {
            dp[i][1][i] = A[i];
        }
        for (int j = 2; j <= K; j++) {
            for (int i = j - 1; i < N; i++) {
                for (int k = j - 2; k < i; k++) {
                    dp[i][j][i] = max(dp[i][j][i], dp[k][j - 1][k] | A[i]);
                }
            }
        }
        int maxCost = 0;
        for (int i = 0; i < N; i++) {
            maxCost = max(maxCost, dp[N - 1][K][i]);
        }
        printf("%d\n", maxCost);
        free(A);
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < K; j++) {
                free(dp[i][j]);
            }
            free(dp[i]);
        }
        free(dp);
    }
    return 0;
}

