import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int[][][] dp = new int[N][K][N];
            for (int i = 0; i < N; i++) {
                dp[i][1][i] = A[i];
            }
            for (int j = 2; j <= K; j++) {
                for (int i = j - 1; i < N; i++) {
                    for (int k = j - 2; k < i; k++) {
                        dp[i][j][i] = Math.max(dp[i][j][i], dp[k][j - 1][k] | A[i]);
                    }
                }
            }
            int maxCost = 0;
            for (int i = 0; i < N; i++) {
                maxCost = Math.max(maxCost, dp[N - 1][K][i]);
            }
            System.out.println(maxCost);
        }
    }
}

