const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, K] = readline().split(' ').map(Number);
    const A = readline().split(' ').map(Number);
    const dp = Array(N).fill(0).map(() => Array(K).fill(0).map(() => Array(N).fill(0)));
    for (let j = 0; j < N; j++) {
        dp[j][1][j] = A[j];
    }
    for (let k = 2; k <= K; k++) {
        for (let j = k - 1; j < N; j++) {
            for (let l = k - 2; l < j; l++) {
                dp[j][k][j] = Math.max(dp[j][k][j], dp[l][k - 1][l] | A[j]);
            }
        }
    }
    let maxCost = 0;
    for (let j = 0; j < N; j++) {
        maxCost = Math.max(maxCost, dp[N - 1][K][j]);
    }
    console.log(maxCost);
